import { TestIds } from '../../constants.js';

const FRAME_INDICATOR_OPACITY = 0.2;
interface AreaIndicatorProps {
  x: number;
  width: number;
  height: number;
  color: string;
  filter: string;
}

export const AreaIndicator = ({
  x,
  width,
  height,
  color,
  filter,
}: AreaIndicatorProps) => (
  <rect
    data-testid={TestIds.AnnotationIndicator}
    x={x}
    width={width}
    height={height}
    fill={color}
    fillOpacity={FRAME_INDICATOR_OPACITY}
    strokeWidth={0}
    filter={filter}
  />
);
